import{_ as n,n as i,p as r,q as d,s as e,R as s,t,Z as c}from"./framework-4bf64526.js";const l="/中断优先级.png",h={},o={href:"https://blog.csdn.net/qq_19799765/article/details/84501917",target:"_blank",rel:"noopener noreferrer"},u=c(`<h2 id="一写博客感觉对定时器中断还不够了解-还有很多没写-上面给大家一个传送门。" tabindex="-1"><a class="header-anchor" href="#一写博客感觉对定时器中断还不够了解-还有很多没写-上面给大家一个传送门。" aria-hidden="true">#</a> 一写博客感觉对定时器中断还不够了解，还有很多没写，上面给大家一个传送门。</h2><h2 id="_1-定时器中断" tabindex="-1"><a class="header-anchor" href="#_1-定时器中断" aria-hidden="true">#</a> 1.定时器中断</h2><h3 id="中断的概念" tabindex="-1"><a class="header-anchor" href="#中断的概念" aria-hidden="true">#</a> 中断的概念</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>中断是指计算机运行过程中，出现某些意外情况需主机干预时，
机器能自动停止正在运行的程序并转入处理新情况的程序，
处理完毕后又返回原被暂停的程序继续运行。

                                —— 百度百科 
                                
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>那么怎么理解中断？看下面的例子。</p><p>你正在追电视剧《神雕侠侣》,正看得入迷的时候，电话响了，你暂停电视剧，去接电话，在接电话的过程中，门铃又响了，你暂时放下电话，去把门打开。如果追电视剧是在执行主程序，那么电话就是中断源，电话铃响了就是中断请求，暂停电视就是现场保护，接电话就是中断响应，门铃响了是更高一级的中断请求，去把门打开，那就是中断嵌套。开完门回来接着聊电话，那是中断返回，接完电话把电视剧暂停打开就是现场恢复。</p><h3 id="中断优先级" tabindex="-1"><a class="header-anchor" href="#中断优先级" aria-hidden="true">#</a> 中断优先级</h3><p>下面是中断优先级的一张图片</p><p><img src="`+l+'" alt="中断优先级"></p><h2 id="定时器中断的使用" tabindex="-1"><a class="header-anchor" href="#定时器中断的使用" aria-hidden="true">#</a> 定时器中断的使用</h2>',10);function _(p,m){const a=i("ExternalLinkIcon");return r(),d("div",null,[e("p",null,[e("a",o,[s("51单片机--定时器中断"),t(a)])]),u])}const b=n(h,[["render",_],["__file","dingshiqizhongduan.html.vue"]]);export{b as default};
